var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"여러분 미하~ 오늘 컨텐츠는 카운터즈 레거시에서 전해드립니다!","JPN":"皆さん、ミハ～今日のコンテンツはカウンターズ・レガシーからお届けします！","ENG":"Hi, everyone. It's me, Miya! I'm here today to introduce Counters Legacy!","TWN":"大家好～今天的內容是從制裁者的遺產那邊得到的消息！"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"이 복장은 그러니까…… 가람 씨가 은근슬쩍 계약서에 넣어둔 조항 때문에…….","JPN":"この服は……えっと……ヒカリさんが契約書にこっそり盛り込んだ条項のせいで……","ENG":"So, this outfit is, um... a clause that Garam secretly included in the contract...","TWN":"這身服裝是因為……嘉蘭小姐偷偷加在契約書裡的條款……"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"그, 그게 아니라 오늘은 제가 메인이라 한번 힘써봤어요……!\xA0\xA0","JPN":"というのは違って……今日は私がメインだから奮発してみました……！\xA0\xA0","ENG":"A-actually, I just wanted to put on something nice since I'm the star of the show today...!\xA0\xA0","TWN":"不，不是的，因為今天我是主角，所以稍微打扮了一下……！"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>■■■</color> 바니걸 차림으로? ㅋㅋㅋ\\n<color=#ffd34c>■■■</color> 복장 뭐임? 벌써부터 고여 버린 거야?","JPN":"<color=#ffd34c>■■■</color> バニーガールの格好で？　ｗｗｗ\\n<color=#ffd34c>■■■</color> 何だよあの服？　もうガチ勢になったのかよ。","ENG":"<color=#ffd34c>■■■</color> In a bunny girl costume? LOL\\n<color=#ffd34c>■■■</color> What's with the outfit? Are you already an expert in the game?","TWN":"<color=#ffd34c>■■■</color> 兔女郎？呵呵呵\\n<color=#ffd34c>■■■</color>那身衣服怎麼回事？這麼懂玩？","SCN":"<color=#ffd34c>■■■</color>兔女郎？哈哈哈\\n<color=#ffd34c>■■■</color> 这是什么装扮？都开始走这种路线了？","DEU":"<color=#ffd34c>■■■</color> In a bunny girl costume? LOL\\n<color=#ffd34c>■■■</color> What's with the outfit? Are you already an expert in the game?","FRA":"<color=#ffd34c>■■■</color> In a bunny girl costume? LOL\\n<color=#ffd34c>■■■</color> What's with the outfit? Are you already an expert in the game?"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"오늘은 하트베리 콜라보를 기념해서, 제가 퀘스트를 기획해 봤거든요.","JPN":"今日はハートベリーコラボを記念して、私がクエストを企画してみました。","ENG":"To commemorate the HRT Berry collaboration, I've planned a quest.","TWN":"今天為了紀念與愛心莓果的聯動，我策劃了一個任務。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"바로~ 미야의 굿즈 수집 퀘스트! 정말 간단하죠?","JPN":"じゃじゃーん～ミヤのグッズコレクトクエスト！　簡単でしょう？","ENG":"It's called! Miya's Merchandise Collecting Quest! Isn't it simple?","TWN":"就是～米婭的周邊收集任務！很簡單吧？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"맵에 표시된 구역에서 미야의 브로마이드를 얻으면 클리어에요.","JPN":"マップに記されたエリアで、ミヤのブロマイドを手に入れたらクリアです。","ENG":"All you have to do is obtain Miya's poster from the area marked on the map.","TWN":"在地圖上標記的區域獲得米婭的海報即可通關。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>■■■</color> 미야의 브로마이드라고????\\n<color=#ffd34c>■■■</color> 대체 무슨 사진을 찍었는데여???","JPN":"<color=#ffd34c>■■■</color> ミヤのブロマイド？？？\\n<color=#ffd34c>■■■</color>どんな写真なんですか？？","ENG":"<color=#ffd34c>■■■</color> Miya's poster????\\n<color=#ffd34c>■■■</color> What kind of photo is it???","TWN":"<color=#ffd34c>■■■</color>米婭的海報？？？\\n<color=#ffd34c>■■■</color>是什麼照片？？？","SCN":"<color=#ffd34c>■■■</color> 米娅的宣传照？？？？\\n<color=#ffd34c>■■■</color>到底拍了什么照片啊？？？","DEU":"<color=#ffd34c>■■■</color> Miya's poster????\\n<color=#ffd34c>■■■</color> What kind of photo is it???","FRA":"<color=#ffd34c>■■■</color> Miya's poster????\\n<color=#ffd34c>■■■</color> What kind of photo is it???"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"무, 무슨 사진이냐고요? 지금 제가 입고 있는…….","JPN":"ど、どんな写真……？　今私が着ている……","ENG":"W-what kind of photo? It's what I'm wearing right–","TWN":"什，什麼照片？就是我現在穿的這件……"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"자세한 건 저희 채널에서 확인해 주세요……!!!","JPN":"詳しい内容は私たちのチャンネルでチェックしてください……！！","ENG":"Check out our channel for more details...!!!","TWN":"詳細內容請在我們的頻道查看……！！！"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"그럼 가볼까요……?","JPN":"では行きましょうか……？","ENG":"Then, shall we...?","TWN":"那麼開始吧……？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"나 참…… 그 땅꼬마 녀석, 설마 하트베리의 스폰 때문에 날 이용한 건 아니겠지?","JPN":"ったく……あのチビ、まさかハートベリーのスポンサー目当てで私を利用したわけじゃないわよね。","ENG":"Ugh... That little kid. She's not using me for that sponsorship with HRT Berry, is she?","TWN":"我說……那個矮冬瓜，不會是因為愛心莓果的贊助才利用我的吧？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"당신이 그…… 하트베리의 보미 맞지? 퀘스트는 여기서 받으면 돼?","JPN":"あんたがその……ハートベリーのボミだよね？　クエストはここで受注すればいいの？","ENG":"You're, uh... Bomi from HRT Berry, right? Is this where I get the quest?","TWN":"你是那個……愛心莓果的普美對吧？任務在這裡領取嗎？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"시시한 퀘스트나 줄 거면 사양할게. 가장 어려운 걸로 줘!","JPN":"つまんないクエストはお断りだから。一番難しいやつにして！","ENG":"If it's a fetch quest, then I'll decline. Give me the hardest one you've got!","TWN":"如果任務很無聊，我可不幹。我要最難的任務！"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"아카데미 학생이냥? 의욕이 넘치는 건 좋은거당.","JPN":"アカデミーの生徒かにゃ？　やる気に満ちているのはいいことだにゃ。","ENG":"Are you a student of the Academy? It's great how energetic you are.","TWN":"是學院的學生嗎？真是充滿幹勁呢。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"하지만 너무 무리하다 깜빡 잠에 들지 않게 조심하라냥.","JPN":"でも無理しすぎてうっかり眠っちゃわないように気をつけるにゃ。","ENG":"But be careful not to fall asleep while pushing yourself.","TWN":"但是不要太勉強自己，不要一不小心就睡著囉喵。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"장소는 맵에 표기해 놨당. 한번 잘 찾아보라냥~","JPN":"場所はマップに印をつけておいたにゃ。頑張って探してみるにゃ～","ENG":"I marked the location on your map. Happy hunting!","TWN":"地點已經標在地圖上了。快去找找看吧～"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"미야의 브로마이드 찾기……? 이딴 게 퀘스트라고……?!","JPN":"ミヤのブロマイド探し……？　こんなのがクエストなの……！？","ENG":"\\"Find Miya's Poster\\"...? This is the quest...?!","TWN":"尋找米婭的海報……？這也算任務嗎……？！"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이봐, 지금 장난치는 거야? 좋은 말 할 때 어서 다른 걸로 내놔!","JPN":"ちょっと、ふざけてるの？　早く他のクエストをよこしなさい！","ENG":"Hey, are you kidding me right now? Take this back and give me something harder!","TWN":"喂，你現在是在開玩笑嗎？趁我還想好好說話的時候，趕緊換個別的出來！"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"이 퀘스트를 얕보면 곤란하당. 벌써부터 경쟁자가 어마어마 하다냥.","JPN":"このクエストを甘く見ちゃ困るにゃ。すでにライバルたちがうじゃうじゃいるにゃ。","ENG":"You shouldn't underestimate this quest. The competition is already fierce.","TWN":"不要小看這個任務。現在已經有很多競爭者了喵。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"방금은 어떤 <color=#ffd34c>총잡이 소녀</color>도 있었는데, 부하들을 잔뜩 모은 것 같았당.","JPN":"さっきは<color=#ffd34c>ガンマン少女</color>もいたけど、部下をたくさんひき連れてきたみたいだったにゃ。","ENG":"I met a <color=#ffd34c>gunslinger girl</color> right before you, and she had a ton of underlings with her.","TWN":"剛才有個<color=#ffd34c>槍手少女</color>，好像召集了一大堆手下呢喵。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"분명 무시무시한 상대가 될거당.","JPN":"きっと恐ろしい相手になるにゃ。","ENG":"I'm sure she'll be a formidable opponent.","TWN":"肯定會成為一個可怕的對手。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥! 피 튀기는 전장은 이 몸에겐 익숙해서 말이야.","JPN":"ふん！　血まみれの戦場なんて、この私には慣れっこよ。","ENG":"Hmph! I'm already used to a bloody battlefield.","TWN":"哼！血腥的戰場對我來說已經習以為常了。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"하, 학생이라고 하지 않았냥……?","JPN":"せ、生徒じゃなかったにゃ……？","ENG":"D-didn't you say you were a student...?","TWN":"我記得你就是個學生吧喵……？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"후후, 부하들을 잔뜩 모아왔다고? 이 몸에게 숫자는 의미 없는데 말이야…….","JPN":"ふふ、部下をたくさん連れてきた？　私に数なんか意味ないのにね……","ENG":"*Scoff* A ton of underlings? Numbers mean nothing to me...","TWN":"呵呵，帶了這麼多手下過來嗎？對我來說，數量沒有任何意義……"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"근데…… 니들은 왜 따라온 거야?","JPN":"ところで……あんたたちはなんでまたついて来たのよ？","ENG":"But... why are you all following me?","TWN":"不過……你們為什麼跟過來了？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};